+
+impl FdRegistrationError {
+    #[must_use]
+    pub const fn reason_code(self) -> &'static str {
+        match self {
+            Self::FdOutOfRange { .. } => "eventloop.fd_out_of_range",
+            Self::FdResizeFailure { .. } => "eventloop.fd_resize_failure",
+        }
